mapper.select:
SELECT COUNT(1) AS totalRequests, COALESCE(SUM(total_tokens), 0) AS totalTokens, COALESCE(SUM(CASE WHEN success = '0' THEN 1 ELSE 0 END), 0) AS successRequests, COALESCE(SUM(CASE WHEN success = '1' THEN 1 ELSE 0 END), 0) AS failedRequests, COALESCE(AVG(latency_ms), 0) AS avgLatencyMs, COALESCE(SUM(prompt_tokens), 0) AS promptTokens, COALESCE(SUM(completion_tokens), 0) AS completionTokens FROM ai_usage_log
AND create_time >= #{beginTime}
AND create_time <= #{endTime}
